import { forwardRef } from 'react';

export interface ArvoLinkProps extends Omit<React.AnchorHTMLAttributes<HTMLAnchorElement>, 'href'> {
  variant?: 'primary' | 'secondary';
  size?: 'sm' | 'lg';
  label: string;
  href: string;
  icon?: string;
  isExternal?: boolean;
  isDisabled?: boolean;
  isVisited?: boolean;
  isLoading?: boolean;
}

const ArvoLink = forwardRef<HTMLAnchorElement, ArvoLinkProps>(
  function ArvoLink(
    {
      variant = 'primary',
      size = 'lg',
      label,
      href,
      icon,
      isExternal = false,
      isDisabled = false,
      isVisited = false,
      isLoading = false,
      target,
      rel,
      className,
      onClick,
      ...rest
    },
    ref
  ) {
    const effectiveTarget = isExternal && !target ? '_blank' : target;
    const needsRel = effectiveTarget === '_blank';
    const effectiveRel = needsRel
      ? rel ?? 'noopener noreferrer'
      : rel;

    const classes = [
      'arvo-lnk',
      `arvo-lnk--${variant}`,
      `arvo-lnk--${size}`,
      isVisited ? 'visited' : '',
      isDisabled ? 'is-disabled' : '',
      isLoading ? 'loading' : '',
      className ?? '',
    ]
      .filter(Boolean)
      .join(' ');

    const blocked = isDisabled || isLoading;

    const handleClick = (e: React.MouseEvent<HTMLAnchorElement>) => {
      if (blocked) {
        e.preventDefault();
        e.stopPropagation();
        return;
      }
      onClick?.(e);
    };

    return (
      <a
        ref={ref}
        href={isDisabled ? undefined : href}
        target={isDisabled ? undefined : effectiveTarget}
        rel={isDisabled ? undefined : effectiveRel}
        className={classes}
        aria-disabled={isDisabled ? true : undefined}
        aria-busy={isLoading ? true : undefined}
        tabIndex={isDisabled ? 0 : undefined}
        onClick={handleClick}
        {...rest}
      >
        {icon && (
          <span
            className={`arvo-lnk__ico o9con o9con-${icon}`}
            aria-hidden="true"
          />
        )}
        <span className="arvo-lnk__lbl">{label}</span>
        {isExternal && (
          <span
            className="arvo-lnk__ext o9con o9con-external-link"
            aria-hidden="true"
          />
        )}
      </a>
    );
  }
);

export default ArvoLink;
